var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>랭크전 모의전투 종료.</color>","JPN":"<color=#ffd34c>ランク戦、模擬戦闘終了。</color>","ENG":"<color=#ffd34c>Ending simulated Ranked Battle.</color>","TWN":"<color=#ffd34c>排位戰模擬戰鬥結束。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L3_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>전투 결과 연산 중...... 완료.</color>","JPN":"<color=#ffd34c>戦闘結果演算中……完了。</color>","ENG":"<color=#ffd34c>Calculating combat results... Completed.</color>","TWN":"<color=#ffd34c>正在演算戰鬥結果……已完成。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>랭킹 순위를 재정렬합니다.</color>","JPN":"<color=#ffd34c>ランキング記録を再整列します。</color>","ENG":"<color=#ffd34c>Rearranging rankings...</color>","TWN":"<color=#ffd34c>正在重新統計排名。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>1등 – 옌 싱 란체스터</color>","JPN":"<color=#ffd34c>1位 – イェン・シング・ランチェスター</color>","ENG":"<color=#ffd34c>1st Place - Yen Xing Lanchester</color>","TWN":"<color=#ffd34c>第1名——嫣杏‧蘭賈斯特</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>2등 – 유미나, 레이. S</color>","JPN":"<color=#ffd34c>2位 – ヤナギ・ミナ、レイ.S</color>","ENG":"<color=#ffd34c>2nd Place - Yoo Mina, Ray S.</color>","TWN":"<color=#ffd34c>第2名——劉米娜＆雷伊.S</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>3등 – 나이엘 블루스틸</color>","JPN":"<color=#ffd34c>3位 – ナイエル・ブルースチール</color>","ENG":"<color=#ffd34c>3rd Place - Naielle Bluesteel</color>","TWN":"<color=#ffd34c>第3名——奈爾‧布魯斯提爾</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"첫 시도에서 랭킹 2위라고? 정말?","JPN":"初挑戦で2位？　本当に？","ENG":"You got 2nd place on the first try? For real?","TWN":"第一次嘗試就獲得排位戰第2名？真的假的？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"1등인 학생회장님은 그렇다 쳐도, 2등은 항상 그 녀석 차지였는데......?","JPN":"1位の生徒会長はわかるけど、2位はいつもあの子だったのに……？","ENG":"I mean, you still haven't managed to overtake the Student President... But that other brat always took 2nd place!","TWN":"第1名是學生會長這沒問題，但第2名一直都是那個傢伙啊……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"으으...... 다 끝났어......?","JPN":"うう……終わった……？","ENG":"Ugh... I-is it over yet?","TWN":"呃呃……結束了嗎……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"어지러워 죽을 것 같아......","JPN":"めまいで死にそう……","ENG":"I'm so dizzy I think I could puke...","TWN":"我快暈死了……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이거 회사에 있는 것보다 성능이 별로 같은데...... 멀미가 너무 심해.","JPN":"これ、会社にあるものより性能が低いのか……酔いがひどいね。","ENG":"I think this machine's not as good as the one back at my workplace... It's giving me serious motion sickness.","TWN":"這個性能好像不如我們公司的那台……太讓人發暈了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선배! 이것 좀 봐요! 벌써 전체 랭킹 2위라고요!","JPN":"先輩！　見てください！　もう全体ランキング2位ですよ！","ENG":"Ray! Look! You're already in 2nd place!","TWN":"前輩！你看！你現在是第2名了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이대로라면 수석 졸업도 꿈이 아니겠어요!","JPN":"このままだと首席卒業も夢じゃないです！","ENG":"You could graduate as a valedictorian at this rate!","TWN":"這樣，你就有可能以第一名的成績畢業了呢！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"무, 무리야. 방금은 단체전이었잖아.","JPN":"む、無理だよ。さっきのは団体戦だったでしょ。","ENG":"N-no way. This was a co-op session.","TWN":"怎，怎麼可能。剛才是團隊戰。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"실제로 적들은 미나 후배가 다 쓰러뜨렸고......","JPN":"実際敵を倒したのはミナだし……","ENG":"Mina beat most of the enemies anyway...","TWN":"實際上敵人都是米娜同學消滅的……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 아닌 것 같은데?","JPN":"そうでもないよ？","ENG":"I don't think so.","TWN":"好像不是哦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기 전투 통계 그래프를 봐. 공격 점수는 내가 높아도 방어는 거의 다 레이 선배가 해 줬어.","JPN":"この戦闘統計グラフを見て。攻撃点数は私が高くても、防御はほとんどレイ先輩がしてくれたよ。","ENG":"Take a look at the battle stats. I may have the higher attack score, but you did most of the defending.","TWN":"你看戰鬥統計圖表。攻擊分數雖然是我高一些，但防禦都是雷伊前輩做的呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"레이 선배가 적들을 막아 주지 않았으면 이렇게 쉽게 클리어 하진 못 했을 거야.","JPN":"レイ先輩が敵を止めてくれなかったら、こんなに簡単にクリアできなかったと思う。","ENG":"If you hadn't fended them all off, we wouldn't have been able to clear it so easily.","TWN":"如果沒有雷伊前輩替我抵擋敵人，我也沒辦法輕鬆通關。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리 회사에 있는 어떤 선배랑은 전혀 다른 모습이었어.","JPN":"うちの会社にいる、ある先輩とは全然違う。","ENG":"If anything, you're nothing like a certain someone I know at work.","TWN":"這跟我們公司的某個前輩完全不一樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"안심하고 전열을 맡길 수 있는 사람이라고 해야 하나?","JPN":"安心して前を任せられるって感じかな？","ENG":"I mean, I can rely on you to defend the line, I guess?","TWN":"可以說你是能讓人放心交付後方的人？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러고 보니......","JPN":"そういえば……","ENG":"Oh... Come to think of it...","TWN":"你這麼一說……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선배는 어수룩해서 평소에도 여기저기 부딪치거나 넘어지는 일이 많거든.","JPN":"先輩はかなりのおっちょこちょいさんで普段あちこちぶつかったり転んだりするんだよ｡","ENG":"He's always bumping into things and falling over.","TWN":"前輩好像平時也迷迷糊糊的，經常撞到或者摔倒。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"가끔은 남들이 다칠 것까지 대신 받아 주는 거 같다니까.","JPN":"たまに他の人の分まで代わりに怪我している気もするの。","ENG":"Sometimes it's almost as if he's getting hurt on everyone else's behalf.","TWN":"有時候我都覺得你是怕別人受傷，所以替人承受傷害。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 일을 많이 겪으면 맷집도 자연스럽게 좋아지는 거 아닐까?","JPN":"そうしているうちに、いろんな面で図太くなってきたのかな？","ENG":"Maybe he learned to take a punch from that?","TWN":"也許這樣的事經歷多了，所以不知不覺間提高了防禦技能？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그거 순 악담 아니야?","JPN":"それ、単なるディスりにも聞こえるね。","ENG":"Is that supposed to be a compliment?","TWN":"你這純屬猜測亂說的吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 괜찮아.","JPN":"いや、いいんだ。","ENG":"It's okay.","TWN":"算了，沒關係。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"정말로 내가 다른 사람들 대신 다치는 거라면 오히려 기쁠 거야.","JPN":"本当に僕が怪我することで他の人が傷つかないなら……嬉しいことかも。","ENG":"If the reason I'm getting hurt all the time is so others don't have to, I'd actually be happy about that.","TWN":"如果真的是能夠代替別人受傷，我反而會高興。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"내가 조금만 참으면 다른 사람들은 고통 받지 않는다는 거잖아.","JPN":"僕が少し我慢すれば他の人が苦しまないということでしょ。","ENG":"That means nobody else has to suffer as long as I can take it.","TWN":"因為這意味著，只要我忍一忍就能讓別人不受痛苦。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선배, 사람이 좋은 것도 정도가 있죠.","JPN":"先輩、お人好しにもほどがありますよ。","ENG":"Come on, Ray. Not even an angel would be that selfless.","TWN":"前輩，做好人也得有個限度。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"보통 사람은 절대 그런 식으로 생각 안 할걸요......","JPN":"それ、普通の人の思考じゃないですよ……","ENG":"Most people would never think of it that way...","TWN":"一般人絕對不會像你這麼想……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 뭐야, 이것들은?","JPN":"うん？　なにこれ？","ENG":"Huh? What's going on here?","TWN":"咦？你們在幹嘛？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};